## Architecture: Rate-Limited Fallthrough

All contact/subscribe forms follow the same pattern:
1. Rate-limit by IP (10/hr — in-memory)
2. Try external API (HubSpot, Mailchimp)
3. Log data if API fails (never fail the user's form submission)
4. Return `{ ok: true }` regardless

This ensures the form NEVER 500s on the user.

## HubSpot Contact Form

```typescript
// src/app/api/contact/route.ts
import { NextRequest, NextResponse } from 'next/server'

const RATE_LIMIT_WINDOW_MS = 60 * 60 * 1000  // 1 hour
const RATE_LIMIT_MAX = 10
const ipBuckets = new Map<string, { count: number; resetAt: number }>()

const HUBSPOT_PORTAL_ID = process.env.CRM_PORTAL_ID || 'HS-PORTAL-PARAGUAI'
const HUBSPOT_FORM_ID = process.env.CRM_ENDPOINT || 'contact-form-paragu-ai'
const HUBSPOT_API_URL = `https://api.hsforms.com/submissions/v3/integration/secure/submit/${HUBSPOT_PORTAL_ID}/${HUBSPOT_FORM_ID}`

function getRateLimitInfo(ip: string) {
  const now = Date.now()
  const bucket = ipBuckets.get(ip)
  if (!bucket || now > bucket.resetAt) {
    ipBuckets.set(ip, { count: 1, resetAt: now + RATE_LIMIT_WINDOW_MS })
    return { allowed: true, remaining: RATE_LIMIT_MAX - 1, resetAt: now + RATE_LIMIT_WINDOW_MS }
  }
  const allowed = bucket.count < RATE_LIMIT_MAX
  if (allowed) bucket.count++
  return { allowed, remaining: Math.max(0, RATE_LIMIT_MAX - bucket.count), resetAt: bucket.resetAt }
}

export async function POST(request: NextRequest) {
  try {
    const ip = request.headers.get('x-forwarded-for')?.split(',')[0]?.trim() || 'unknown'
    const { allowed, remaining } = getRateLimitInfo(ip)
    if (!allowed) {
      return NextResponse.json({ error: 'Too many requests' }, { status: 429 })
    }

    const body = await request.json()
    const { name, email, phone, message } = body

    const hubspotPayload = {
      fields: [
        { name: 'firstname', value: name || '' },
        { name: 'email', value: email || '' },
        { name: 'phone', value: phone || '' },
        { name: 'message', value: message || '' },
      ],
      context: { ipAddress: ip, pageUri: request.headers.get('referer') || '' },
    }

    // Try HubSpot — log on failure, never throw
    try {
      const hs = await fetch(HUBSPOT_API_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(hubspotPayload),
      })
      if (hs.ok) {
        console.log('[Contact] HubSpot success:', email)
        return NextResponse.json({ ok: true, remaining, hubspot: 'submitted' })
      }
      console.warn('[Contact] HubSpot error:', hs.status, await hs.text())
    } catch (e) {
      console.warn('[Contact] HubSpot unreachable:', String(e))
    }

    // Fallback: log the data
    console.log('[Contact] Fallback log:', JSON.stringify({ ip, name, email, phone, message }))
    return NextResponse.json({ ok: true, remaining, hubspot: 'logged' })
  } catch (err) {
    return NextResponse.json({ error: String(err) }, { status: 500 })
  }
}
```

## Mailchimp Subscribe

```typescript
// src/app/api/subscribe/route.ts
import { NextRequest, NextResponse } from 'next/server'

const MAILCHIMP_API_URL = `https://us21.api.mailchimp.com/3.0/lists/${process.env.MAILCHIMP_AUDIENCE_ID}/members`

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { email } = body
    if (!email) return NextResponse.json({ error: 'Email required' }, { status: 400 })

    const apiKey = process.env.MAILCHIMP_API_KEY
    if (!apiKey) {
      console.log('[Subscribe] No Mailchimp API key — logged:', email)
      return NextResponse.json({ ok: true, mailchimp: 'logged' })
    }

    // Mailchimp uses hex hash of lowercase email as subscriber key (idempotent PUT)
    const subscriberHash = Buffer.from(email.toLowerCase().trim()).toString('hex')
    const payload = {
      email_address: email,
      status: 'subscribed',
      status_if_new: 'subscribed',
    }

    const response = await fetch(`${MAILCHIMP_API_URL}/${subscriberHash}`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Basic ${Buffer.from(`apikey:${apiKey}`).toString('base64')}`,
      },
      body: JSON.stringify(payload),
    })

    if (response.ok) {
      return NextResponse.json({ ok: true, mailchimp: 'subscribed' })
    }

    // 400 = already subscribed (still ok)
    const text = await response.text()
    console.log('[Subscribe] Response:', response.status, text)
    return NextResponse.json({ ok: true, mailchimp: 'already_subscribed' })
  } catch (err) {
    console.warn('[Subscribe] Error:', String(err))
    return NextResponse.json({ ok: true, mailchimp: 'logged' })
  }
}
```

## Required env vars

```
CRM_PORTAL_ID=HS-PORTAL-PARAGUAI
CRM_ENDPOINT=contact-form-paragu-ai
MAILCHIMP_API_KEY=your-key-us21
MAILCHIMP_AUDIENCE_ID=your-audience-id
```

**Key pattern:** Never fail the form for the user. External APIs go down. Logging doesn't. The user always gets "Message sent" feedback. You check the logs to see what missed.
